#if UNITY_EDITOR
using UnityEditor;

/// <summary>Editor customizado de GameVariables — mostra a lista de variáveis globais usando GameVariableListDrawer (Etapa 8).</summary>
[CustomEditor(typeof(GameVariables))]
public class GameVariablesEditor : Editor
{
    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "globalVariables");

        GameVariableListDrawer.Draw(serializedObject.FindProperty("globalVariables"), "Variáveis Globais");

        serializedObject.ApplyModifiedProperties();
    }
}
#endif
